1	//! Model Context Protocol (MCP) server вҖ” JSON-RPC over HTTP.
2	//!
3	//! Exposes the Agent Nervous System as MCP tools for Claude, ChatGPT,
4	//! and other MCP-compatible AI agents.
5	//!
6	//! Specification: https://spec.modelcontextprotocol.io
7	
8	use serde_json::{json, Value};
9	
10	use crate::client::InternalClient;
11	
12	const MCP_VERSION: &str = "2024-11-05";
13	
14	/// MCP server state shared across requests.
15	#[derive(Clone)]
16	pub struct McpServer {
17	    client: InternalClient,
18	}
19	
20	impl McpServer {
21	    pub fn new(client: InternalClient) -> Self {
22	        Self { client }
23	    }
24	
25	    /// Handle an incoming JSON-RPC request. Returns the JSON-RPC response.
26	    pub async fn handle_request(&self, body: Value) -> Value {
27	        let id = body.get("id").cloned();
28	        let method = body.get("method").and_then(|m| m.as_str()).unwrap_or("");
29	
30	        match method {
31	            "initialize" => self.handle_initialize(id),
32	            "tools/list" => self.handle_tools_list(id),
33	            "tools/call" => self.handle_tools_call(id, &body).await,
34	            _ => json_rpc_error(id, -32601, &format!("Method not found: {}", method)),
35	        }
36	    }
37	
38	    fn handle_initialize(&self, id: Option<Value>) -> Value {
39	        json_rpc_result(
40	            id,
41	            json!({
42	                "protocolVersion": MCP_VERSION,
43	                "serverInfo": {
44	                    "name": "agent-nervous-system",
45	                    "version": env!("CARGO_PKG_VERSION")
46	                },
47	                "capabilities": {
48	                    "tools": {}
49	                }
50	            }),
51	        )
52	    }
53	
54	    fn handle_tools_list(&self, id: Option<Value>) -> Value {
55	        json_rpc_result(
56	            id,
57	            json!({
58	                "tools": [
59	                    {
60	                        "name": "create_session",
61	                        "description": "Create a new browser session for an agent goal",
62	                        "inputSchema": {
63	                            "type": "object",
64	                            "properties": {
65	                                "goal_id": { "type": "string", "description": "Goal ID this session belongs to" },
66	                                "start_url": { "type": "string", "description": "Initial URL to load (default: about:blank)" }
67	                            },
68	                            "required": ["goal_id"]
69	                        }
70	                    },
71	                    {
72	                        "name": "navigate",
73	                        "description": "Navigate the browser to a URL",
74	                        "inputSchema": {
75	                            "type": "object",
76	                            "properties": {
77	                                "url": { "type": "string", "description": "The URL to navigate to" },
78	                                "session_id": { "type": "string", "description": "Browser session ID" }
79	                            },
80	                            "required": ["url", "session_id"]
81	                        }
82	                    },
83	                    {
84	                        "name": "click",
85	                        "description": "Click an element on the page",
86	                        "inputSchema": {
87	                            "type": "object",
88	                            "properties": {
89	                                "selector": { "type": "string", "description": "CSS selector for the element" },
90	                                "session_id": { "type": "string", "description": "Browser session ID" }
91	                            },
92	                            "required": ["selector", "session_id"]
93	                        }
94	                    },
95	                    {
96	                        "name": "type_text",
97	                        "description": "Type text into an input element",
98	                        "inputSchema": {
99	                            "type": "object",
100	                            "properties": {
101	                                "selector": { "type": "string", "description": "CSS selector for the input" },
102	                                "value": { "type": "string", "description": "Text to type" },
103	                                "session_id": { "type": "string", "description": "Browser session ID" }
104	                            },
105	                            "required": ["selector", "value", "session_id"]
106	                        }
107	                    },
108	                    {
109	                        "name": "scroll",
110	                        "description": "Scroll the page",
111	                        "inputSchema": {
112	                            "type": "object",
113	                            "properties": {
114	                                "session_id": { "type": "string", "description": "Browser session ID" },
115	                                "value": { "type": "string", "description": "Scroll amount or direction (e.g. 'down', 'up', '100')" }
116	                            },
117	                            "required": ["session_id"]
118	                        }
119	                    },
120	                    {
121	                        "name": "screenshot",
122	                        "description": "Capture a screenshot of the current page",
123	                        "inputSchema": {
124	                            "type": "object",
125	                            "properties": {
126	                                "session_id": { "type": "string", "description": "Browser session ID" },
127	                                "full_page": { "type": "boolean", "description": "Capture full scrollable page" }
128	                            },
129	                            "required": ["session_id"]
130	                        }
131	                    },
132	                    {
133	                        "name": "get_dom",
134	                        "description": "Get the distilled DOM of the current page",
135	                        "inputSchema": {
136	                            "type": "object",
137	                            "properties": {
138	                                "session_id": { "type": "string", "description": "Browser session ID" },
139	                                "mode": {
140	                                    "type": "string",
141	                                    "description": "Distillation mode: text_only (reading), input_fields (forms), all_fields (debug)"
142	                                }
143	                            },
144	                            "required": ["session_id"]
145	                        }
146	                    },
147	                    {
148	                        "name": "execute_action",
149	                        "description": "Execute any browser action (click, type, scroll, select, submit, wait, navigate, screenshot)",
150	                        "inputSchema": {
151	                            "type": "object",
152	                            "properties": {
153	                                "session_id": { "type": "string", "description": "Browser session ID" },
154	                                "action_type": { "type": "string", "description": "Action type: click, type, scroll, select, navigate, submit, wait, screenshot" },
155	                                "selector": { "type": "string", "description": "CSS selector for the target element" },
156	                                "value": { "type": "string", "description": "Value for type/select/scroll actions" }
157	                            },
158	                            "required": ["session_id", "action_type"]
159	                        }
160	                    },
161	                    {
162	                        "name": "check_goal",
163	                        "description": "Check the progress of a goal",
164	                        "inputSchema": {
165	                            "type": "object",
166	                            "properties": {
167	                                "goal_id": { "type": "string", "description": "Goal ID to check" }
168	                            },
169	                            "required": ["goal_id"]
170	                        }
171	                    },
172	                    {
173	                        "name": "create_goal",
174	                        "description": "Create a new goal for the agent to pursue",
175	                        "inputSchema": {
176	                            "type": "object",
177	                            "properties": {
178	                                "description": { "type": "string", "description": "What the agent needs to accomplish" },
179	                                "context": { "type": "string", "description": "Additional context for the goal" },
180	                                "max_steps": { "type": "integer", "description": "Maximum action steps allowed" }
181	                            },
182	                            "required": ["description"]
183	                        }
184	                    }
185	                ]
186	            }),
187	        )
188	    }
189	
190	    async fn handle_tools_call(&self, id: Option<Value>, body: &Value) -> Value {
191	        let params = body.get("params");
192	        let tool_name = match params.and_then(|p| p.get("name")).and_then(|n| n.as_str()) {
193	            Some(name) => name,
194	            None => return json_rpc_error(id, -32602, "Missing params.name"),
195	        };
196	
197	        let args = params
198	            .and_then(|p| p.get("arguments"))
199	            .cloned()
200	            .unwrap_or(json!({}));
201	
202	        let result = match tool_name {
203	            "create_session" => self.tool_create_session(&args).await,
204	            "navigate" => self.tool_navigate(&args).await,
205	            "click" => self.tool_click(&args).await,
206	            "type_text" => self.tool_type_text(&args).await,
207	            "scroll" => self.tool_scroll(&args).await,
208	            "screenshot" => self.tool_screenshot(&args).await,
209	            "get_dom" => self.tool_get_dom(&args).await,
210	            "execute_action" => self.tool_execute_action(&args).await,
211	            "check_goal" => self.tool_check_goal(&args).await,
212	            "create_goal" => self.tool_create_goal(&args).await,
213	            other => return json_rpc_error(id, -32602, &format!("Unknown tool: {}", other)),
214	        };
215	
216	        match result {
217	            Ok(content) => json_rpc_result(
218	                id,
219	                json!({ "content": [{ "type": "text", "text": content }] }),
220	            ),
221	            Err(e) => json_rpc_error(id, -32000, &e),
222	        }
223	    }
224	
225	    // в”Җв”Җ Tool implementations в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
226	
227	    fn str_arg<'a>(args: &'a Value, key: &str) -> Option<&'a str> {
228	        args.get(key).and_then(|v| v.as_str())
229	    }
230	
231	    async fn tool_create_session(&self, args: &Value) -> Result<String, String> {
232	        let goal_id = Self::str_arg(args, "goal_id").unwrap_or("");
233	        let start_url = Self::str_arg(args, "start_url").unwrap_or("about:blank");
234	
235	        let mut client = self.client.clone_client();
236	        let req = tonic::Request::new(ans_proto::ans::CreateSessionRequest {
237	            goal_id: goal_id.into(),
238	            start_url: start_url.into(),
239	            headers: std::collections::HashMap::new(),
240	        });
241	
242	        let resp = client
243	            .create_session(req)
244	            .await
245	            .map_err(|e| format!("gRPC error: {}", e))?
246	            .into_inner();
247	
248	        Ok(serde_json::to_string_pretty(&json!({
249	            "session_id": resp.session_id,
250	            "goal_id": resp.goal_id,
251	            "status": resp.status,
252	            "created_at": resp.created_at,
253	        }))
254	        .unwrap_or_else(|e| format!("serialization error: {e}")))
255	    }
256	
257	    async fn tool_navigate(&self, args: &Value) -> Result<String, String> {
258	        let session_id = Self::str_arg(args, "session_id").ok_or("session_id required")?;
259	        let url = Self::str_arg(args, "url").ok_or("url required")?;
260	
261	        let mut client = self.client.clone_client();
262	        let req = tonic::Request::new(ans_proto::ans::NavigateRequest {
263	            session_id: session_id.into(),
264	            url: url.into(),
265	            timeout_ms: 30000,
266	        });
267	
268	        let resp = client
269	            .navigate(req)
270	            .await
271	            .map_err(|e| format!("gRPC error: {}", e))?
272	            .into_inner();
273	
274	        Ok(serde_json::to_string_pretty(&json!({
275	            "url": resp.url,
276	            "title": resp.title,
277	            "loaded": resp.loaded,
278	            "dom_node_count": resp.dom_node_count,
279	        }))
280	        .unwrap_or_else(|e| format!("serialization error: {e}")))
281	    }
282	
283	    async fn tool_execute_action(&self, args: &Value) -> Result<String, String> {
284	        let session_id = Self::str_arg(args, "session_id").ok_or("session_id required")?;
285	        let action_type = Self::str_arg(args, "action_type").ok_or("action_type required")?;
286	        let selector = Self::str_arg(args, "selector").unwrap_or("");
287	        let value = Self::str_arg(args, "value").unwrap_or("");
288	
289	        let mut client = self.client.clone_client();
290	        let req = tonic::Request::new(ans_proto::ans::ExecuteActionRequest {
291	            session_id: session_id.into(),
292	            action: Some(ans_proto::ans::Action {
293	                action_type: action_type.into(),
294	                selector: selector.into(),
295	                value: value.into(),
296	                params: std::collections::HashMap::new(),
297	            }),
298	        });
299	
300	        let resp = client
301	            .execute_action(req)
302	            .await
303	            .map_err(|e| format!("gRPC error: {}", e))?
304	            .into_inner();
305	
306	        Ok(serde_json::to_string_pretty(&json!({
307	            "success": resp.success,
308	            "error_message": resp.error_message,
309	            "execution_time_ms": resp.execution_time_ms,
310	        }))
311	        .unwrap_or_else(|e| format!("serialization error: {e}")))
312	    }
313	
314	    async fn tool_click(&self, args: &Value) -> Result<String, String> {
315	        let session_id = Self::str_arg(args, "session_id").ok_or("session_id required")?;
316	        let selector = Self::str_arg(args, "selector").ok_or("selector required")?;
317	
318	        let action_args = json!({
319	            "session_id": session_id,
320	            "action_type": "click",
321	            "selector": selector,
322	            "value": ""
323	        });
324	        self.tool_execute_action(&action_args).await
325	    }
326	
327	    async fn tool_type_text(&self, args: &Value) -> Result<String, String> {
328	        let session_id = Self::str_arg(args, "session_id").ok_or("session_id required")?;
329	        let selector = Self::str_arg(args, "selector").ok_or("selector required")?;
330	        let value = Self::str_arg(args, "value").ok_or("value required")?;
331	
332	        let action_args = json!({
333	            "session_id": session_id,
334	            "action_type": "type",
335	            "selector": selector,
336	            "value": value
337	        });
338	        self.tool_execute_action(&action_args).await
339	    }
340	
341	    async fn tool_scroll(&self, args: &Value) -> Result<String, String> {
342	        let session_id = Self::str_arg(args, "session_id").ok_or("session_id required")?;
343	        let value = Self::str_arg(args, "value").unwrap_or("down");
344	
345	        let action_args = json!({
346	            "session_id": session_id,
347	            "action_type": "scroll",
348	            "selector": "",
349	            "value": value
350	        });
351	        self.tool_execute_action(&action_args).await
352	    }
353	
354	    async fn tool_screenshot(&self, args: &Value) -> Result<String, String> {
355	        let session_id = Self::str_arg(args, "session_id").ok_or("session_id required")?;
356	        let full_page = args
357	            .get("full_page")
358	            .and_then(|v| v.as_bool())
359	            .unwrap_or(false);
360	
361	        let mut client = self.client.clone_client();
362	        let req = tonic::Request::new(ans_proto::ans::ScreenshotRequest {
363	            session_id: session_id.into(),
364	            format: "png".into(),
365	            quality: 80,
366	            full_page,
367	            arrow_shm_key: String::new(),
368	        });
369	
370	        let resp = client
371	            .capture_screenshot(req)
372	            .await
373	            .map_err(|e| format!("gRPC error: {}", e))?
374	            .into_inner();
375	
376	        Ok(serde_json::to_string_pretty(&json!({
377	            "success": resp.success,
378	            "size_bytes": resp.size_bytes,
379	            "format": resp.format,
380	            "data_base64_len": resp.data.len(),
381	        }))
382	        .unwrap_or_else(|e| format!("serialization error: {e}")))
383	    }
384	
385	    async fn tool_get_dom(&self, args: &Value) -> Result<String, String> {
386	        let session_id = Self::str_arg(args, "session_id").ok_or("session_id required")?;
387	        let mode = Self::str_arg(args, "mode").unwrap_or("input_fields");
388	
389	        let mut client = self.client.clone_client();
390	        let req = tonic::Request::new(ans_proto::ans::DomRequest {
391	            session_id: session_id.into(),
392	            mode: mode.into(),
393	        });
394	
395	        let resp = client
396	            .get_distilled_dom(req)
397	            .await
398	            .map_err(|e| format!("gRPC error: {}", e))?
399	            .into_inner();
400	
401	        Ok(serde_json::to_string_pretty(&json!({
402	            "mode": resp.mode,
403	            "url": resp.url,
404	            "title": resp.title,
405	            "element_count": resp.elements.len(),
406	            "interactive_count": resp.interactive.len(),
407	        }))
408	        .unwrap_or_else(|e| format!("serialization error: {e}")))
409	    }
410	
411	    async fn tool_check_goal(&self, args: &Value) -> Result<String, String> {
412	        let goal_id = Self::str_arg(args, "goal_id").ok_or("goal_id required")?;
413	
414	        let mut client = self.client.clone_client();
415	        let req = tonic::Request::new(ans_proto::ans::GoalStateRequest {
416	            goal_id: goal_id.into(),
417	        });
418	
419	        let resp = client
420	            .get_goal_state(req)
421	            .await
422	            .map_err(|e| format!("gRPC error: {}", e))?
423	            .into_inner();
424	
425	        Ok(serde_json::to_string_pretty(&json!({
426	            "goal_id": resp.goal_id,
427	            "description": resp.description,
428	            "status": resp.status,
429	            "progress": resp.progress,
430	            "sub_goals": resp.sub_goals.len(),
431	            "created_at": resp.created_at,
432	        }))
433	        .unwrap_or_else(|e| format!("serialization error: {e}")))
434	    }
435	
436	    async fn tool_create_goal(&self, args: &Value) -> Result<String, String> {
437	        let description = Self::str_arg(args, "description").ok_or("description required")?;
438	        let context_str = Self::str_arg(args, "context").unwrap_or("");
439	        let max_steps = args
440	            .get("max_steps")
441	            .and_then(|v| v.as_i64())
442	            .unwrap_or(100) as i32;
443	
444	        let mut context = std::collections::HashMap::new();
445	        if !context_str.is_empty() {
446	            context.insert("context".into(), context_str.into());
447	        }
448	
449	        let mut client = self.client.clone_client();
450	        let req = tonic::Request::new(ans_proto::ans::CreateGoalRequest {
451	            description: description.into(),
452	            context,
453	            max_budget_cents: 500,
454	            max_steps,
455	        });
456	
457	        let resp = client
458	            .create_goal(req)
459	            .await
460	            .map_err(|e| format!("gRPC error: {}", e))?
461	            .into_inner();
462	
463	        Ok(serde_json::to_string_pretty(&json!({
464	            "goal_id": resp.goal_id,
465	            "description": resp.description,
466	            "status": resp.status,
467	            "progress": resp.progress,
468	        }))
469	        .unwrap_or_else(|e| format!("serialization error: {e}")))
470	    }
471	}
472	
473	// в”Җв”Җ JSON-RPC helpers в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
474	
475	fn json_rpc_result(id: Option<Value>, result: Value) -> Value {
476	    json!({
477	        "jsonrpc": "2.0",
478	        "id": id.unwrap_or(Value::Null),
479	        "result": result
480	    })
481	}
482	
483	fn json_rpc_error(id: Option<Value>, code: i32, message: &str) -> Value {
484	    json!({
485	        "jsonrpc": "2.0",
486	        "id": id.unwrap_or(Value::Null),
487	        "error": {
488	            "code": code,
489	            "message": message
490	        }
491	    })
492	}
493	
494	#[cfg(test)]
495	mod tests {
496	    use super::*;
497	
498	    #[test]
499	    fn test_json_rpc_result_format() {
500	        let result = json_rpc_result(Some(json!(1)), json!({"ok": true}));
501	        assert_eq!(result["jsonrpc"], "2.0");
502	        assert_eq!(result["id"], 1);
503	        assert_eq!(result["result"]["ok"], true);
504	    }
505	
506	    #[test]
507	    fn test_json_rpc_error_format() {
508	        let error = json_rpc_error(Some(json!(2)), -32601, "Not found");
509	        assert_eq!(error["jsonrpc"], "2.0");
510	        assert_eq!(error["id"], 2);
511	        assert_eq!(error["error"]["code"], -32601);
512	    }
513	}
