503	    async fn classify_distractions(
504	        &self,
505	        request: Request<DistractionRequest>,
506	    ) -> Result<Response<DistractionList>, Status> {
507	        let req = request.into_inner();
508	        let url = req.url;
509	
510	        // Extract CSS class/id hints from DOM elements for distraction pattern matching
511	        let css_hints = req
512	            .dom
513	            .as_ref()
514	            .map(|dom| {
515	                dom.elements
516	                    .iter()
517	                    .flat_map(|el| {
518	                        el.attributes
519	                            .iter()
520	                            .filter(|(k, _)| *k == "class" || *k == "id")
521	                            .map(|(_, v)| v.clone())
522	                    })
523	                    .collect::<Vec<_>>()
524	                    .join(" ")
525	            })
526	            .unwrap_or_default();
527	
528	        // Extract all visible text from the distilled DOM for content scanning
529	        let dom_text = req
530	            .dom
531	            .as_ref()
532	            .map(|dom| {
533	                dom.elements
534	                    .iter()
535	                    .map(|el| el.text.as_str())
536	                    .collect::<Vec<_>>()
537	                    .join(" ")
538	            })
539	            .unwrap_or_default();
540	
541	        let classifier = ans_immune::DistractionClassifier;
542	        let flags = classifier.classify(&url, &dom_text, &css_hints);
543	
544	        let distractions: Vec<_> = flags
545	            .iter()
546	            .map(ans_immune::serialization::distraction_to_proto_list_item)
547	            .collect();
548	
549	        Ok(Response::new(DistractionList {
550	            distractions,
551	            classification_time_us: 0,
552	        }))
553	    }
