681	            ans_budget::serialization::budget_status_to_proto(&status, &req.goal_id),
682	        ))
683	    }
684	
685	    async fn configure_budget(
686	        &self,
687	        request: Request<BudgetConfigRequest>,
688	    ) -> Result<Response<BudgetConfig>, Status> {
689	        let req = request.into_inner();
690	        let config = ans_budget::serialization::proto_to_budget_config(&req);
691	
692	        {
693	            let mut tracker = self.budget.lock().await;
694	            tracker.configure(config);
695	        }
696	
697	        let tracker = self.budget.lock().await;
698	        let proto_config = ans_budget::serialization::budget_config_to_proto(tracker.config());
699	
700	        Ok(Response::new(proto_config))
701	    }
702	
703	    // в”Җв”Җ Health в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
704	
705	    async fn health(&self, _request: Request<Empty>) -> Result<Response<HealthStatus>, Status> {
706	        Ok(Response::new(HealthStatus {
707	            healthy: true,
708	            version: env!("CARGO_PKG_VERSION").into(),
709	            active_sessions: self.sessions.session_count() as i32,
710	            active_goals: 0,
711	            uptime_seconds: 0,
712	            total_actions_executed: 0,
713	            total_decisions_stored: 0,
714	            budget_mode: "normal".into(),
715	            metrics: std::collections::HashMap::new(),
716	        }))
717	    }
718	}
719	
720	// в”Җв”Җ Helpers в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
721	
722	/// Return type uses tonic::Status вҖ” large Err is inherent to gRPC handlers.
723	#[allow(clippy::result_large_err)]
724	fn parse_distill_mode(s: &str) -> Result<DistillMode, Status> {
725	    match s {
726	        "text_only" => Ok(DistillMode::TextOnly),
727	        "input_fields" => Ok(DistillMode::InputFields),
728	        "all_fields" => Ok(DistillMode::AllFields),
729	        _ => Err(Status::invalid_argument(format!(
730	            "unknown distill mode: {}",
731	            s
732	        ))),
733	    }
734	}
735	
736	#[allow(clippy::result_large_err)]
737	fn parse_uuid(s: &str, field: &str) -> Result<Uuid, Status> {
738	    Uuid::parse_str(s).map_err(|_| Status::invalid_argument(format!("invalid {} UUID", field)))
739	}
740	
741	fn optional_string(s: &str) -> Option<String> {
742	    if s.is_empty() {
743	        None
744	    } else {
745	        Some(s.to_string())
746	    }
747	}
748	
749	fn now_epoch_ms() -> i64 {
750	    chrono::Utc::now().timestamp_millis()
751	}
752	
753	#[allow(clippy::result_large_err)]
754	fn proto_to_core_action(
755	    proto: &ans_proto::ans::Action,
756	) -> Result<ans_core::session::Action, Status> {
757	    use ans_core::session::ActionType;
758	    use std::collections::HashMap;
759	
760	    let action_type = match proto.action_type.as_str() {
761	        "click" => ActionType::Click,
762	        "type" => ActionType::Type,
763	        "scroll" => ActionType::Scroll,
764	        "select" => ActionType::Select,
765	        "navigate" => ActionType::Navigate,
766	        "wait" => ActionType::Wait,
767	        "submit" => ActionType::Submit,
768	        "screenshot" => ActionType::Screenshot,
769	        other => {
770	            return Err(Status::invalid_argument(format!(
771	                "unknown action_type: {}",
772	                other
773	            )))
774	        }
775	    };
776	
777	    Ok(ans_core::session::Action {
778	        action_type,
779	        selector: optional_string(&proto.selector),
780	        value: optional_string(&proto.value),
781	        params: proto
782	            .params
783	            .iter()
784	            .map(|(k, v)| (k.clone(), v.clone()))
785	            .collect::<HashMap<_, _>>(),
786	    })
787	}
788	
789	/// Map [`GoalStatus`] to a streaming event type string.
790	fn goal_status_event(status: &ans_core::goal::GoalStatus) -> String {
791	    match status {
792	        ans_core::goal::GoalStatus::Pending => "created",
793	        ans_core::goal::GoalStatus::Active => "progress",
794	        ans_core::goal::GoalStatus::Completed => "completed",
795	        ans_core::goal::GoalStatus::Failed => "failed",
796	        ans_core::goal::GoalStatus::Blocked => "blocked",
797	    }
798	    .into()
799	}
800	
801	/// Convert a proto [`ans_proto::ans::EyeReport`] to core [`ans_core::signal::EyeReport`].
802	/// Returns `None` if the eye_name is unrecognized or the content is missing.
803	fn proto_to_core_eye_report(
804	    proto: &ans_proto::ans::EyeReport,
805	) -> Option<ans_core::signal::EyeReport> {
806	    use ans_proto::ans::eye_report::Content;
807	
808	    let eye_name = match proto.eye_name.as_str() {
809	        "dom_reader" => EyeName::DomReader,
810	        "vision" => EyeName::Vision,
811	        "page_diff" => EyeName::PageDiff,
812	        "goal_verifier" => EyeName::GoalVerifier,
813	        "error_detector" => EyeName::ErrorDetector,
814	        _ => return None,
815	    };
816	
817	    let content = match &proto.content {
818	        Some(Content::Dom(dom)) => EyeReportContent::DomReport {
819	            elements: vec![],
820	            interactive: vec![],
821	            mode: dom
822	                .dom
823	                .as_ref()
824	                .map(|d| match d.mode.as_str() {
825	                    "text_only" => DistillMode::TextOnly,
826	                    "input_fields" => DistillMode::InputFields,
827	                    _ => DistillMode::AllFields,
828	                })
829	                .unwrap_or(DistillMode::AllFields),
830	        },
831	        Some(Content::Vision(v)) => EyeReportContent::VisionReport {
832	            visible_elements: v.visible_elements.clone(),
833	            overlays: v.overlays.clone(),
834	            blocked_regions: v.blocked_regions.clone(),
835	            page_type: v.page_type.clone(),
836	            anomalies: v.anomalies.clone(),
837	            raw_response: v.raw_response.clone(),
838	        },
839	        Some(Content::Diff(d)) => {
840	            let diff_report = d.diff.as_ref();
841	            EyeReportContent::DiffReport {
842	                added: diff_report.map_or(vec![], |r| {
843	                    r.added.iter().map(|e| e.selector.clone()).collect()
844	                }),
845	                removed: diff_report.map_or(vec![], |r| {
846	                    r.removed.iter().map(|e| e.selector.clone()).collect()
847	                }),
848	                modified: diff_report.map_or(vec![], |r| {
849	                    r.modified.iter().map(|m| m.selector.clone()).collect()
850	                }),
851	                visual_diff_pct: diff_report.map_or(0.0, |r| r.visual_diff_percentage),
852	                summary: diff_report.map_or(String::new(), |r| r.summary.clone()),
853	            }
854	        }
855	        Some(Content::Verification(v)) => EyeReportContent::Verification {
856	            sub_goal_advanced: v.criteria_status == "met",
857	            confidence: v.confidence,
858	            reasoning: v.reasoning.clone(),
859	            criteria_status: v.criteria_status.clone(),
860	        },
861	        Some(Content::Error(e)) => EyeReportContent::ErrorReport {
862	            failure_type: e.failure_type.clone(),
863	            description: e.description.clone(),
864	            recovery_actions: e.recovery_actions.clone(),
865	            should_retry: e.should_retry,
866	            max_retries: e.max_retries as u32,
867	        },
868	        None => return None,
869	    };
870	
871	    Some(ans_core::signal::EyeReport {
872	        eye_name,
873	        timestamp: chrono::Utc::now(),
874	        confidence: proto.confidence,
875	        goal_relevance: proto.goal_relevance,
876	        content,
877	    })
878	}
879	
880	/// Format the oneof eye report content into a readable string.
881	fn format_eye_content(content: &Option<ans_proto::ans::eye_report::Content>) -> String {
882	    use ans_proto::ans::eye_report::Content;
883	    match content {
884	        Some(Content::Dom(dom)) => {
885	            format!(
886	                "DOM: {} elements, {} interactive",
887	                dom.dom.as_ref().map_or(0, |d| d.elements.len() as i32),
888	                dom.focused_elements.len()
889	            )
890	        }
891	        Some(Content::Vision(v)) => {
892	            format!(
893	                "Vision: {} visible, {} overlays, type={}",
894	                v.visible_elements.len(),
895	                v.overlays.len(),
896	                v.page_type
897	            )
898	        }
899	        Some(Content::Diff(d)) => {
900	            format!(
901	                "Diff: {}% visual change",
902	                d.diff.as_ref().map_or(0.0, |r| r.visual_diff_percentage)
903	            )
904	        }
905	        Some(Content::Verification(v)) => {
906	            format!(
907	                "Verify: {} (confidence={:.0}%)",
908	                v.criteria_status,
909	                v.confidence * 100.0
910	            )
911	        }
912	        Some(Content::Error(e)) => {
913	            format!("Error: {} вҖ” {}", e.failure_type, e.description)
914	        }
915	        None => "no content".into(),
916	    }
917	}
918

