37	            .unwrap_or("about:blank");
38	
39	        let mut client = self.client.clone_client();
40	        let req = tonic::Request::new(ans_proto::ans::CreateSessionRequest {
41	            goal_id: goal_id.into(),
42	            start_url: start_url.into(),
43	            headers: std::collections::HashMap::new(),
44	        });
45	
46	        match client.create_session(req).await {
47	            Ok(resp) => {
48	                let r = resp.into_inner();
49	                Json(json!({
50	                    "session_id": r.session_id,
51	                    "goal_id": r.goal_id,
52	                    "status": r.status,
53	                    "created_at": r.created_at,
54	                    "last_activity_at": r.last_activity_at,
55	                }))
56	            }
57	            Err(e) => Json(json!({
58	                "error": format!("gRPC error: {}", e)
59	            })),
60	        }
61	    }
62	
63	    /// POST /api/v1/sessions/:id/navigate вҖ” navigate browser to URL.
64	    pub async fn navigate(&self, session_id: &str, body: Value) -> Json<Value> {
65	        let url = body
66	            .get("url")
67	            .and_then(|v| v.as_str())
68	            .unwrap_or("about:blank");
69	
70	        let mut client = self.client.clone_client();
71	        let req = tonic::Request::new(ans_proto::ans::NavigateRequest {
72	            session_id: session_id.into(),
73	            url: url.into(),
74	            timeout_ms: 30000,
75	        });
76	
