//! REST API for non-MCP agents.
//!
//! Mounted at `/api/v1/`. Provides simple HTTP endpoints for agents
//! that don't speak MCP. All endpoints require an API key.

use axum::response::Json;
use serde_json::{json, Value};

use crate::client::InternalClient;

/// Shared REST API state.
#[derive(Clone)]
pub struct ApiRouter {
    client: InternalClient,
}

impl ApiRouter {
    pub fn new(client: InternalClient) -> Self {
        Self { client }
    }

    /// Health check вҖ” no auth required.
    pub async fn health(&self) -> Json<Value> {
        Json(json!({
            "status": "ok",
            "version": env!("CARGO_PKG_VERSION"),
            "gateway": "ans-gateway"
        }))
    }

    /// POST /api/v1/sessions вҖ” create a new browser session.
    pub async fn create_session(&self, body: Value) -> Json<Value> {
        let goal_id = body.get("goal_id").and_then(|v| v.as_str()).unwrap_or("");
        let start_url = body
            .get("start_url")
            .and_then(|v| v.as_str())
            .unwrap_or("about:blank");

        let mut client = self.client.clone_client();
        let req = tonic::Request::new(ans_proto::ans::CreateSessionRequest {
            goal_id: goal_id.into(),
            start_url: start_url.into(),
            headers: std::collections::HashMap::new(),
        });

        match client.create_session(req).await {
            Ok(resp) => {
                let r = resp.into_inner();
                Json(json!({
                    "session_id": r.session_id,
                    "goal_id": r.goal_id,
                    "status": r.status,
                    "created_at": r.created_at,
                    "last_activity_at": r.last_activity_at,
                }))
            }
            Err(e) => Json(json!({
                "error": format!("gRPC error: {}", e)
            })),
        }
    }

    /// POST /api/v1/sessions/:id/navigate вҖ” navigate browser to URL.
    pub async fn navigate(&self, session_id: &str, body: Value) -> Json<Value> {
        let url = body
            .get("url")
            .and_then(|v| v.as_str())
            .unwrap_or("about:blank");

        let mut client = self.client.clone_client();
        let req = tonic::Request::new(ans_proto::ans::NavigateRequest {
            session_id: session_id.into(),
            url: url.into(),
            timeout_ms: 30000,
        });

        match client.navigate(req).await {
            Ok(resp) => {
                let r = resp.into_inner();
                Json(json!({
                    "session_id": session_id,
                    "url": r.url,
                    "title": r.title,
                    "loaded": r.loaded,
                    "dom_node_count": r.dom_node_count,
                }))
            }
            Err(e) => Json(json!({
                "error": format!("gRPC error: {}", e)
            })),
        }
    }

    /// POST /api/v1/sessions/:id/execute вҖ” execute a browser action.
    pub async fn execute_action(&self, session_id: &str, body: Value) -> Json<Value> {
        let action_type = body
            .get("action_type")
            .and_then(|v| v.as_str())
            .unwrap_or("click");
        let selector = body.get("selector").and_then(|v| v.as_str()).unwrap_or("");
        let value = body.get("value").and_then(|v| v.as_str()).unwrap_or("");

        let mut client = self.client.clone_client();
        let req = tonic::Request::new(ans_proto::ans::ExecuteActionRequest {
            session_id: session_id.into(),
            action: Some(ans_proto::ans::Action {
                action_type: action_type.into(),
                selector: selector.into(),
                value: value.into(),
                params: std::collections::HashMap::new(),
            }),
        });

        match client.execute_action(req).await {
            Ok(resp) => {
                let r = resp.into_inner();
                Json(json!({
                    "session_id": session_id,
                    "success": r.success,
                    "error_message": r.error_message,
                    "execution_time_ms": r.execution_time_ms,
                }))
            }
            Err(e) => Json(json!({
                "error": format!("gRPC error: {}", e)
            })),
        }
    }

    /// POST /api/v1/sessions/:id/screenshot вҖ” capture screenshot.
    pub async fn screenshot(&self, session_id: &str, body: Value) -> Json<Value> {
        let full_page = body
            .get("full_page")
            .and_then(|v| v.as_bool())
            .unwrap_or(false);
        let format = body.get("format").and_then(|v| v.as_str()).unwrap_or("png");

        let mut client = self.client.clone_client();
        let req = tonic::Request::new(ans_proto::ans::ScreenshotRequest {
            session_id: session_id.into(),
            format: format.into(),
            quality: 80,
            full_page,
            arrow_shm_key: String::new(),
        });

        match client.capture_screenshot(req).await {
            Ok(resp) => {
                let r = resp.into_inner();
                Json(json!({
                    "session_id": session_id,
                    "success": r.success,
                    "format": r.format,
                    "size_bytes": r.size_bytes,
                    "data_base64_len": r.data.len(),
                }))
            }
            Err(e) => Json(json!({
                "error": format!("gRPC error: {}", e)
            })),
        }
    }

    /// GET /api/v1/sessions/:id/dom вҖ” get distilled DOM.
    pub async fn get_dom(&self, session_id: &str) -> Json<Value> {
        let mut client = self.client.clone_client();
        let req = tonic::Request::new(ans_proto::ans::DomRequest {
            session_id: session_id.into(),
            mode: "input_fields".into(),
        });

        match client.get_distilled_dom(req).await {
            Ok(resp) => {
                let r = resp.into_inner();
                Json(json!({
                    "session_id": session_id,
                    "mode": r.mode,
                    "url": r.url,
                    "title": r.title,
                    "element_count": r.elements.len(),
                    "interactive_count": r.interactive.len(),
                    "semantic_block_count": r.semantic_blocks.len(),
                }))
            }
            Err(e) => Json(json!({
                "error": format!("gRPC error: {}", e)
            })),
        }
    }

    /// GET /api/v1/goals/:id вҖ” get goal state.
    pub async fn get_goal(&self, goal_id: &str) -> Json<Value> {
        let mut client = self.client.clone_client();
        let req = tonic::Request::new(ans_proto::ans::GoalStateRequest {
            goal_id: goal_id.into(),
        });

        match client.get_goal_state(req).await {
            Ok(resp) => {
                let r = resp.into_inner();
                Json(json!({
                    "goal_id": r.goal_id,
                    "description": r.description,
                    "status": r.status,
                    "progress": r.progress,
                    "sub_goals": r.sub_goals.len(),
                    "created_at": r.created_at,
                }))
            }
            Err(e) => Json(json!({
                "error": format!("gRPC error: {}", e)
            })),
        }
    }

    /// POST /api/v1/goals вҖ” create a new goal.
    pub async fn create_goal(&self, body: Value) -> Json<Value> {
        let description = body
            .get("description")
            .and_then(|v| v.as_str())
            .unwrap_or("");
        let context_str = body.get("context").and_then(|v| v.as_str()).unwrap_or("");
        let max_steps = body
            .get("max_steps")
            .and_then(|v| v.as_i64())
            .unwrap_or(100) as i32;

        let mut context = std::collections::HashMap::new();
        if !context_str.is_empty() {
            context.insert("context".into(), context_str.into());
        }

        let mut client = self.client.clone_client();
        let req = tonic::Request::new(ans_proto::ans::CreateGoalRequest {
            description: description.into(),
            context,
            max_budget_cents: 500,
            max_steps,
        });

        match client.create_goal(req).await {
            Ok(resp) => {
                let r = resp.into_inner();
                Json(json!({
                    "goal_id": r.goal_id,
                    "description": r.description,
                    "status": r.status,
                    "progress": r.progress,
                }))
            }
            Err(e) => Json(json!({
                "error": format!("gRPC error: {}", e)
            })),
        }
    }
}

