//! Decision record CRUD and vector search.
//!
//! In-memory store with cosine similarity search. LanceDB integration
//! with IVF_PQ index is deferred to a future phase when Arrow/Lance
//! columnar storage is fully wired.

use std::sync::RwLock;

use ans_core::decision::DecisionRecord;

/// Thread-safe in-memory decision store with vector similarity search.
pub struct DecisionStore {
    records: RwLock<Vec<DecisionRecord>>,
}

impl DecisionStore {
    /// Create a new empty decision store.
    pub fn new() -> Self {
        Self {
            records: RwLock::new(Vec::new()),
        }
    }

    /// Insert a decision record. Returns the total count after insert.
    pub fn insert(&self, record: DecisionRecord) -> usize {
        let mut records = self.records.write().expect("lock poisoned");
        records.push(record);
        records.len()
    }

    /// Total number of stored records.
    pub fn len(&self) -> usize {
        self.records.read().expect("lock poisoned").len()
    }

    /// Whether the store is empty.
    pub fn is_empty(&self) -> bool {
        self.len() == 0
    }

    /// Query top-k decisions by cosine similarity to the given embedding.
    /// Returns records sorted by similarity descending, filtered by min_score.
    pub fn query_similar(
        &self,
        embedding: &[f32],
        k: usize,
        min_score: f32,
    ) -> Vec<(DecisionRecord, f32)> {
        let records = self.records.read().expect("lock poisoned");
        if records.is_empty() {
            return Vec::new();
        }

        let mut scored: Vec<(usize, f32)> = records
            .iter()
            .enumerate()
            .filter_map(|(i, r)| {
                let sim = cosine_similarity(embedding, &r.context_embedding);
                if sim >= min_score {
                    Some((i, sim))
                } else {
                    None
                }
            })
            .collect();

        // Sort descending by similarity
        scored.sort_by(|a, b| b.1.partial_cmp(&a.1).unwrap_or(std::cmp::Ordering::Equal));

        scored
            .into_iter()
            .take(k)
            .map(|(i, sim)| (records[i].clone(), sim))
            .collect()
    }
}

impl Default for DecisionStore {
    fn default() -> Self {
        Self::new()
    }
}

/// Cosine similarity between two vectors.
fn cosine_similarity(a: &[f32], b: &[f32]) -> f32 {
    if a.is_empty() || b.is_empty() {
        return 0.0;
    }

    let min_len = a.len().min(b.len());
    let mut dot = 0.0f32;
    let mut norm_a = 0.0f32;
    let mut norm_b = 0.0f32;

    for i in 0..min_len {
        dot += a[i] * b[i];
        norm_a += a[i] * a[i];
        norm_b += b[i] * b[i];
    }

    // Add remaining squared terms for the longer vector's norm
    for v in a.iter().skip(min_len) {
        norm_a += v * v;
    }
    for v in b.iter().skip(min_len) {
        norm_b += v * v;
    }

    let denom = (norm_a.sqrt() * norm_b.sqrt()).max(f32::EPSILON);
    dot / denom
}

#[cfg(test)]
#[allow(clippy::unwrap_used)]
mod tests {
    use super::*;
    use ans_core::decision::BusinessOutcome;
    use ans_core::session::{Action, ActionType};
    use chrono::Utc;
    use uuid::Uuid;

    fn make_record(id: Uuid, embedding: Vec<f32>, score: f32) -> DecisionRecord {
        DecisionRecord {
            id,
            session_id: Uuid::nil(),
            goal_id: Uuid::nil(),
            action: Action {
                action_type: ActionType::Click,
                selector: Some("#btn".into()),
                value: None,
                params: std::collections::HashMap::new(),
            },
            tool: "cdp_click".into(),
            context_type: "form_fill".into(),
            context_embedding: embedding,
            business_outcome: BusinessOutcome::new_immediate(true, None),
            outcome_success: true,
            results_summary: String::new(),
            error_message: None,
            composite_score: score,
            use_count: 1,
            created_at: Utc::now(),
            updated_at: Utc::now(),
        }
    }

    #[test]
    fn test_insert_and_count() {
        let store = DecisionStore::new();
        assert_eq!(store.len(), 0);
        store.insert(make_record(Uuid::new_v4(), vec![1.0, 0.0, 0.0], 0.9));
        assert_eq!(store.len(), 1);
    }

    #[test]
    fn test_cosine_similarity_identical() {
        let v = vec![1.0, 2.0, 3.0];
        assert!((cosine_similarity(&v, &v) - 1.0).abs() < 0.001);
    }

    #[test]
    fn test_cosine_similarity_orthogonal() {
        let a = vec![1.0, 0.0, 0.0];
        let b = vec![0.0, 1.0, 0.0];
        assert!((cosine_similarity(&a, &b) - 0.0).abs() < 0.001);
    }

    #[test]
    fn test_query_similar_returns_best_match() {
        let store = DecisionStore::new();
        store.insert(make_record(Uuid::new_v4(), vec![1.0, 0.0], 0.5));
        store.insert(make_record(Uuid::new_v4(), vec![0.9, 0.1], 0.8));

        let query = vec![1.0, 0.0];
        let results = store.query_similar(&query, 2, 0.0);
        assert_eq!(results.len(), 2);
        // First result should be most similar to [1.0, 0.0]
        assert!(results[0].1 >= results[1].1);
    }

    #[test]
    fn test_min_score_filter() {
        let store = DecisionStore::new();
        store.insert(make_record(Uuid::new_v4(), vec![1.0, 0.0], 0.9));
        store.insert(make_record(Uuid::new_v4(), vec![0.0, 1.0], 0.1));

        let query = vec![1.0, 0.0];
        let results = store.query_similar(&query, 10, 0.8);
        // Only the [1.0, 0.0] record should pass the min_score filter
        assert_eq!(results.len(), 1);
    }
}

//! Layer 1 External API Gateway.
//!
//! How external AI agents connect to the Agent Nervous System.
//! Three protocols, one gateway:
//!
//! - **MCP server** (Model Context Protocol): JSON-RPC tool provider
//!   for Claude, ChatGPT, and other MCP-compatible agents.
//! - **REST API**: Simple HTTP endpoints for non-MCP agents.
//! - **WebSocket**: Streaming events for real-time agent feedback.
//!
//! All connections are authenticated (API key), rate-limited, and
//! budget-tracked before any internal gRPC call is made.

pub mod auth;
pub mod client;
pub mod mcp;
pub mod rest;
pub mod ws;

use std::net::SocketAddr;
use std::sync::Arc;

use axum::routing::{get, post};
use axum::Router;

use auth::SharedKeyRegistry;
use client::InternalClient;
use mcp::McpServer;
use rest::ApiRouter;
use ws::WebSocketServer;

/// Shared gateway state, created once at startup.
#[derive(Clone)]
pub struct Gateway {
    key_registry: SharedKeyRegistry,
    mcp: McpServer,
    rest: ApiRouter,
    ws: WebSocketServer,
}

impl Gateway {
    /// Initialize the gateway: load API keys, connect to the daemon.
    pub async fn init() -> Result<Self, Box<dyn std::error::Error>> {
        let key_registry = Arc::new(auth::KeyRegistry::load(None)?);
        let internal = InternalClient::connect().await?;
        let mcp = McpServer::new(internal.clone());
        let rest = ApiRouter::new(internal.clone());
        let ws = WebSocketServer::new(internal.clone());

        Ok(Self {
            key_registry,
            mcp,
            rest,
            ws,
        })
    }

    /// Build the axum router with all routes mounted and auth applied.
    pub fn router(&self) -> Router {
        let mcp = self.mcp.clone();
        let rest = self.rest.clone();
        let ws = self.ws.clone();
        let auth_layer = auth::AuthLayer::new(Arc::clone(&self.key_registry));

        // Health endpoint вҖ” no auth required
        let health_rest = rest.clone();
        let router = Router::new()
            // MCP endpoint вҖ” no auth (MCP clients authenticate via headers differently)
            .route(
                "/mcp",
                post(
                    move |body: axum::extract::Json<serde_json::Value>| async move {
                        let response = mcp.handle_request(body.0).await;
                        axum::Json(response)
                    },
                ),
            )
            // WebSocket upgrade вҖ” auth handled during handshake
            .route(
                "/ws",
                get(
                    move |ws_upgrade: axum::extract::ws::WebSocketUpgrade| async move {
                        ws.handle_upgrade(ws_upgrade).await
                    },
                ),
            )
            // Public health endpoint вҖ” no auth
            .route(
                "/api/v1/health",
                get(move || {
                    let rest = health_rest.clone();
                    async move { rest.health().await }
                }),
            )
            // Protected REST API вҖ” auth applied
            .nest(
                "/api/v1",
                Router::new()
                    .route(
                        "/sessions",
                        post({
                            let rest = rest.clone();
                            move |axum::extract::Json(body): axum::extract::Json<
                                serde_json::Value,
                            >| async move { rest.create_session(body).await }
                        }),
                    )
                    .route(
                        "/sessions/{id}/navigate",
                        post({
                            let rest = rest.clone();
                            move |axum::extract::Path(id): axum::extract::Path<String>,
                                  axum::extract::Json(body): axum::extract::Json<
                                serde_json::Value,
                            >| async move { rest.navigate(&id, body).await }
                        }),
                    )
                    .route(
                        "/sessions/{id}/execute",
                        post({
                            let rest = rest.clone();
                            move |axum::extract::Path(id): axum::extract::Path<String>,
                                  axum::extract::Json(body): axum::extract::Json<
                                serde_json::Value,
                            >| async move {
                                rest.execute_action(&id, body).await
                            }
                        }),
                    )
                    .route(
                        "/sessions/{id}/screenshot",
                        post({
                            let rest = rest.clone();
                            move |axum::extract::Path(id): axum::extract::Path<String>,
                                  axum::extract::Json(body): axum::extract::Json<
                                serde_json::Value,
                            >| async move {
                                rest.screenshot(&id, body).await
                            }
                        }),
                    )
                    .route(
                        "/sessions/{id}/dom",
                        get({
                            let rest = rest.clone();
                            move |axum::extract::Path(id): axum::extract::Path<String>| async move {
                                rest.get_dom(&id).await
                            }
                        }),
                    )
                    .route(
                        "/goals",
                        post({
                            let rest = rest.clone();
                            move |axum::extract::Json(body): axum::extract::Json<
                                serde_json::Value,
                            >| async move { rest.create_goal(body).await }
                        }),
                    )
                    .route(
                        "/goals/{id}",
                        get({
                            let rest = rest.clone();
                            move |axum::extract::Path(id): axum::extract::Path<String>| async move {
                                rest.get_goal(&id).await
                            }
                        }),
                    )
                    .layer(auth_layer),
            );
        router
    }

    /// Start the gateway HTTP server on the given address.
    /// Blocks until the server exits.
    pub async fn serve(self, addr: SocketAddr) -> Result<(), Box<dyn std::error::Error>> {
        let router = self.router();

        tracing::info!("Gateway starting on {}", addr);

        let listener = tokio::net::TcpListener::bind(addr).await?;
        axum::serve(listener, router).await?;

        Ok(())
    }
}
